<template><div class="page" v-loading="loading"><div class="header"><div><h1>注销申请详情</h1><p>{{d?.application?.applicationNo}}</p></div><div><el-button v-if="d?.application?.status==='DRAFT'" type="primary" @click="submit">提交审批</el-button><el-button v-if="d?.executable&&canExecute" type="danger" @click="execute">执行注销</el-button></div></div><el-alert v-if="d&&!d.executable" :title="d.executionRestriction" type="info" :closable="false"/><el-card v-if="d" shadow="never"><el-descriptions border :column="2"><el-descriptions-item label="注销编号">{{d.cancellation.cancellationNo}}</el-descriptions-item><el-descriptions-item label="状态"><StatusTag :status="d.cancellation.businessStatus"/></el-descriptions-item><el-descriptions-item label="对象类型">{{d.cancellation.cancelObjectType}}</el-descriptions-item><el-descriptions-item label="原因">{{d.cancellation.cancelReasonCode}}</el-descriptions-item><el-descriptions-item label="事件日期">{{d.cancellation.eventDate}}</el-descriptions-item><el-descriptions-item label="当前家庭户">{{d.target?.householdNo||'—'}}</el-descriptions-item></el-descriptions></el-card><el-card v-if="d" shadow="never"><template #header><div class="header"><span>证明材料</span><div v-if="d.application.status==='DRAFT'"><el-select v-model="materialType" style="width:230px;margin-right:8px"><el-option v-for="t in types" :key="t" :value="t"/></el-select><el-upload style="display:inline-block" :show-file-list="false" :http-request="upload"><el-button>上传</el-button></el-upload></div></div></template><el-table :data="d.materials" border><el-table-column prop="materialType" label="类型"/><el-table-column prop="materialName" label="名称"/><el-table-column prop="verifyStatus" label="核验"/></el-table></el-card></div></template>
<script setup>import{computed,onMounted,ref}from'vue';import{useRoute}from'vue-router';import{ElMessage,ElMessageBox}from'element-plus';import{getCancellationDetail,executePersonCancellation,executeHouseholdCancellation}from'../../api/cancellations';import{submitApplication,uploadMaterial}from'../../api/applications';import{useUserStore}from'../../stores/user';import StatusTag from'../../components/common/StatusTag.vue';const route=useRoute(),user=useUserStore(),d=ref(),loading=ref(false),materialType=ref('APPLICANT_IDENTITY_PROOF'),types=['DEATH_CERTIFICATE','DECLARED_DEAD_JUDGMENT','SETTLEMENT_ABROAD_PROOF','DUPLICATE_REGISTRATION_PROOF','CANCELLATION_APPLICATION','HOUSEHOLD_CANCELLATION_PROOF','HOUSEHOLD_MERGE_PROOF','APPLICANT_IDENTITY_PROOF','RELATIONSHIP_PROOF','HOUSEHOLD_BOOK','OTHER_SUPPORTING_DOCUMENT'];const canExecute=computed(()=>user.hasPermission('cancellation:execute'));async function load(){loading.value=true;try{d.value=await getCancellationDetail(route.params.id)}finally{loading.value=false}}async function submit(){await ElMessageBox.confirm('确认提交注销申请审批？','提交确认');await submitApplication(route.params.id);ElMessage.success('已提交');load()}async function execute(){const person=d.value.cancellation.cancelObjectType==='PERSON';await ElMessageBox.confirm(person?'执行后人员将不再具有当前有效户籍，历史档案保留且本阶段不能撤销。确认继续？':'销户后保留历史快照，原户号不能继续接收迁入。确认继续？','高风险操作',{type:'warning'});await(person?executePersonCancellation:executeHouseholdCancellation)(route.params.id,d.value.cancellation.version);ElMessage.success('注销执行完成');load()}async function upload(o){const f=new FormData();f.append('file',o.file);f.append('materialType',materialType.value);f.append('materialName',o.file.name);f.append('requiredFlag','true');await uploadMaterial(route.params.id,f,o.onProgress);load()}onMounted(load);</script><style scoped>.page{display:flex;flex-direction:column;gap:16px}.header{display:flex;justify-content:space-between;align-items:center}.header h1{margin:0}.header p{color:#64748b}</style>
